import { customElement, html, property, state, when } from '@umbraco-cms/backoffice/external/lit';
import { FormsInputFormElement } from '@umbraco-forms/components';
import { splitStringToArray } from '@umbraco-cms/backoffice/utils';
import { UmbLitElement } from '@umbraco-cms/backoffice/lit-element';
import { UmbPropertyEditorConfigCollection, UmbPropertyEditorUiElement } from '@umbraco-cms/backoffice/property-editor';
import FormsInputThemeElement from '../../components/input-theme/input-theme.element';
import { UmbInputDocumentElement } from '@umbraco-cms/backoffice/document';

export type FormDetails = {
  formId: string | null,
  theme: string | null,
  redirectToPageId: string | null
}

const elementName = "forms-form-details-property-editor";

@customElement(elementName)
export class FormsFormDetailsPickerPropertyPickerElement extends UmbLitElement implements UmbPropertyEditorUiElement {

  #value: FormDetails = {
    formId : null,
    theme: null,
    redirectToPageId: null
  };

  @property({ type: Object })
  set value(value: FormDetails) {
    this.#value = value ? structuredClone(value) : this.#value;
  }

  get value(): FormDetails {
    return this.#value;
  }

  @state()
  private _includeThemePicker: boolean = false;

  @state()
  private _includeRedirectPicker: boolean = false;

  @state()
  private _allowedForms: Array<string> = [];

  @state()
  private _allowedFolders: Array<string> = [];

  public set config(config: UmbPropertyEditorConfigCollection | undefined) {
    this._includeThemePicker = config?.getValueByAlias('includeThemePicker') || false;
    this._includeRedirectPicker = config?.getValueByAlias('includeRedirectPicker') || false;
    this._allowedFolders = config?.getValueByAlias('allowedFolders') || [];
    this._allowedForms = config?.getValueByAlias('allowedForms') || [];
  }

  #onPickedFormsChange(event: Event) {
    const target = event.target as FormsInputFormElement;
    this.value.formId = target.selection.length > 0 ? target.selection[0] : null;
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  #onThemeChange(event: Event) {
    const target = event.target as FormsInputThemeElement;
    this.value.theme = target.value;
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  #onRedirectToPageChange(e: CustomEvent) {
    const redirectToPageId = (e.target as UmbInputDocumentElement).value as string;
    this.value.redirectToPageId = redirectToPageId !== "" ? redirectToPageId : null
    this.dispatchEvent(new CustomEvent('property-value-change'));
  }

  render() {
    return html`
      <umb-property-layout
        alias="form"
        .label=${this.localize.term("formPicker_form")}
      >
        <forms-input-form
          id="form"
          .selection=${this.value?.formId ? splitStringToArray(this.value.formId) : []}
          .multiple=${false}
          .allowedFolders=${this._allowedFolders}
          .allowedForms=${this._allowedForms}
          @change=${this.#onPickedFormsChange}
          slot="editor"></forms-input-form>
      </umb-property-layout>

      ${when(this._includeThemePicker,
        () => html`
          <umb-property-layout
            alias="theme"
            .label=${this.localize.term("formPicker_theme")}
          >
            <forms-input-theme
                  @change=${this.#onThemeChange}
                  .value=${this.value?.theme || ""}
                  slot="editor"></forms-input-theme>
          </umb-property-layout>`
      )}

      ${when(this._includeRedirectPicker,
        () => html`
          <umb-property-layout
            alias="theme"
            .label=${this.localize.term("formPicker_redirectToPage")}
            .description=${this.localize.term("formPicker_redirectToPageDescription")}
          >
          <umb-input-document
              slot="editor"
              .value=${this.value?.redirectToPageId || ""}
              max="1"
              @change=${this.#onRedirectToPageChange}
            ></umb-input-document>
          </umb-property-layout>        `
      )}
      `;
  }
}

export default FormsFormDetailsPickerPropertyPickerElement;

declare global {
    interface HTMLElementTagNameMap {
        [elementName]: FormsFormDetailsPickerPropertyPickerElement;
    }
}
